import { json, error } from '@sveltejs/kit';
import type { PageServerLoad } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';

export const load: PageServerLoad = async ({ params }) => {
	const milestone = await getMilestone(db, params.id);
	if (!milestone) {
		throw error(404, `里程碑 ${params.id} 不存在`);
	}
	return { milestone };
};

// Simple toast notification system
// Usage in any component: import { toast } from '$lib/stores/toast'; toast.show('message', 'success');

interface ToastItem {
	id: number;
	message: string;
	type: 'success' | 'error' | 'info';
}

let toasts = $state<ToastItem[]>([]);
let nextId = $state(0);

function show(message: string, type: ToastItem['type'] = 'info', duration = 4000) {
	const id = nextId++;
	toasts.push({ id, message, type });
	setTimeout(() => {
		toasts = toasts.filter((t) => t.id !== id);
	}, duration);
}

export function getToasts() {
	return toasts;
}

export const toast = { show };

import { z } from 'zod';

// ── LLM output schemas ──────────────────────────────────────────────────────

/** A single task inside a decomposed module. */
export const decomposeTaskSchema = z.object({
	title: z.string().min(1, 'Task title is required').max(500, 'Task title too long'),
	description: z.string().max(5000).optional()
});
export type DecomposeTask = z.infer<typeof decomposeTaskSchema>;

/** A single decomposed module produced by the LLM. */
export const decomposeModuleSchema = z.object({
	name: z.string().min(1, 'Module name is required').max(200, 'Module name too long'),
	description: z.string().max(5000).optional(),
	tasks: z.array(decomposeTaskSchema).min(0)
});
export type DecomposeModule = z.infer<typeof decomposeModuleSchema>;

// ── SSE event types ─────────────────────────────────────────────────────────

/** Union discriminator for SSE events sent to the frontend. */
export type DecomposeEvent = DecomposeModuleEvent | DecomposeErrorEvent | DecomposeDoneEvent;

/** A successfully parsed and validated module chunk. */
export interface DecomposeModuleEvent {
	type: 'module';
	index: number;
	module: DecomposeModule;
}

/** An error occurred during the decompose stream. */
export interface DecomposeErrorEvent {
	type: 'error';
	stage: 'connecting' | 'streaming' | 'parsing';
	message: string;
}

/** Signal that the stream is complete. */
export interface DecomposeDoneEvent {
	type: 'done';
	total: number;
	errors: number;
}

/**
 * POST /api/milestones/:id/decompose
 *
 * Thin SSE wrapper around streamDecompose().
 * Validates preconditions (exists, has sourceMd, status=draft),
 * then streams DecomposeEvents as standard SSE.
 */

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';
import { streamDecompose } from '$lib/server/decompose-service.js';
import type { DecomposeEvent } from '$lib/schemas/decompose.js';

// ── SSE formatting helpers ──────────────────────────────────────────────────

function formatSSE(event: DecomposeEvent): string {
	return `event: ${event.type}\ndata: ${JSON.stringify(event)}\n\n`;
}

// ── Handler ──────────────────────────────────────────────────────────────────

export const POST: RequestHandler = async ({ params }) => {
	const milestone = await getMilestone(db, params.id);

	// 404 — milestone not found
	if (!milestone) {
		return json(
			{ error: 'not_found', message: `Milestone ${params.id} not found` },
			{ status: 404 }
		);
	}

	// 400 — no source markdown to decompose
	if (!milestone.sourceMd) {
		return json(
			{ error: 'bad_request', message: 'Milestone has no source markdown to decompose' },
			{ status: 400 }
		);
	}

	// 400 — only draft milestones can be decomposed
	if (milestone.status !== 'draft') {
		return json(
			{ error: 'bad_request', message: `Milestone status is '${milestone.status}', expected 'draft'` },
			{ status: 400 }
		);
	}

	// Stream SSE events from the decompose service
	const generator = streamDecompose(milestone.sourceMd);

	const stream = new ReadableStream({
		async start(controller) {
			const encoder = new TextEncoder();
			try {
				for await (const event of generator) {
					controller.enqueue(encoder.encode(formatSSE(event)));
				}
				controller.close();
			} catch (err: any) {
				// If the controller is still open, send an error event and close
				try {
					const errorEvent: DecomposeEvent = {
						type: 'error',
						stage: 'streaming',
						message: err.message
					};
					controller.enqueue(encoder.encode(formatSSE(errorEvent)));
					controller.close();
				} catch {
					// Controller already closed — nothing to do
				}
			}
		}
	});

	return new Response(stream, {
		headers: {
			'Content-Type': 'text/event-stream',
			'Cache-Control': 'no-cache',
			'Connection': 'keep-alive'
		}
	});
};

/**
 * Decompose service — orchestrates LLM-based milestone decomposition.
 *
 * 1. Reads the milestone's source markdown
 * 2. Sends it to the LLM with a structured system prompt
 * 3. Incrementally parses the streaming JSON array response
 * 4. Validates each module with Zod as it becomes available
 * 5. Yields SSE events (module / error / done)
 *
 * No data is written to the database — that's S03's responsibility.
 */

import { LlmClient } from './llm-client.js';
import {
	decomposeModuleSchema,
	type DecomposeModule,
	type DecomposeEvent,
	type DecomposeModuleEvent,
	type DecomposeErrorEvent,
	type DecomposeDoneEvent
} from '$lib/schemas/decompose.js';

// ── System prompt ────────────────────────────────────────────────────────────

const SYSTEM_PROMPT = `你是一个专业的项目管理助手。你的任务是将需求文档拆解为结构化的模块和任务。

## 输出格式

你必须且只能输出一个 JSON 数组，不要包含任何其他文本、注释或 markdown 标记。

\`\`\`json
[
  {
    "name": "模块名称",
    "description": "模块的简要描述",
    "tasks": [
      {
        "title": "任务标题",
        "description": "任务的详细描述（可选）"
      }
    ]
  }
]
\`\`\`

## 拆解原则

1. 每个模块应该是内聚的、可独立开发和交付的功能单元
2. 每个任务应该是明确的、可验证的工作项
3. 模块之间应该有清晰的边界和最小依赖
4. 任务粒度适中：太大需要再拆分，太小则合并
5. 保持模块名称简洁（2-10 个字），描述清晰
6. 任务标题应该是动作导向的（如"实现XX功能"而非"XX功能"）
7. 按照逻辑依赖顺序排列模块

## 注意事项

- 只输出 JSON 数组，不要输出其他任何内容
- 如果需求文档不清晰，根据上下文做出合理推断
- 每个模块至少包含一个任务
- 确保所有任务合起来能覆盖需求文档的全部内容`;

// ── Incremental JSON object extractor ───────────────────────────────────────

/**
 * Tracks brace depth, string state, and escape state to extract
 * complete JSON objects from a streaming byte buffer.
 *
 * Handles:
 * - Nested objects and arrays
 * - Strings containing braces and brackets
 * - Escaped characters inside strings
 * - Multiple complete objects in one chunk
 * - Objects split across chunks
 */
export function extractCompleteJsonObjects(buffer: string): {
	objects: string[];
	remaining: string;
} {
	const objects: string[] = [];
	let depth = 0;
	let inString = false;
	let escaped = false;
	let objStart = -1;

	for (let i = 0; i < buffer.length; i++) {
		const ch = buffer[i];

		if (escaped) {
			escaped = false;
			continue;
		}

		if (ch === '\\' && inString) {
			escaped = true;
			continue;
		}

		if (ch === '"') {
			inString = !inString;
			continue;
		}

		if (inString) continue;

		if (ch === '{' || ch === '[') {
			if (depth === 0) {
				objStart = i;
			}
			depth++;
		} else if (ch === '}' || ch === ']') {
			depth--;
			if (depth === 0 && objStart !== -1) {
				objects.push(buffer.slice(objStart, i + 1));
				objStart = -1;
			}
		}
	}

	return {
		objects,
		remaining: objStart !== -1 ? buffer.slice(objStart) : ''
	};
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Stream-decompose a milestone's source markdown into modules via LLM.
 *
 * @param sourceMd - The raw markdown content of the milestone
 * @param client   - Optional LlmClient instance (for testing / custom config)
 *
 * Yields `DecomposeEvent` objects:
 * - `{ type: 'module', index, module }` — successfully validated module
 * - `{ type: 'error', stage, message }` — error during the process
 * - `{ type: 'done', total, errors }` — stream complete
 */
export async function* streamDecompose(
	sourceMd: string,
	client?: LlmClient
): AsyncGenerator<DecomposeEvent> {
	const llm = client ?? new LlmClient();
	let moduleIndex = 0;
	let errorCount = 0;
	let jsonBuffer = '';

	const userMessage = `请将以下需求文档拆解为模块和任务：\n\n${sourceMd}`;

	try {
		// Phase 1: Connecting
		for await (const chunk of llm.chatCompletionStream(SYSTEM_PROMPT, userMessage)) {
			jsonBuffer += chunk;

			// Try to extract complete objects from the buffer
			const { objects, remaining } = extractCompleteJsonObjects(jsonBuffer);
			jsonBuffer = remaining;

			for (const jsonStr of objects) {
				// The extracted JSON might be an array (the LLM wraps modules in [])
				let candidates: unknown[];
				try {
					const parsed = JSON.parse(jsonStr);
					candidates = Array.isArray(parsed) ? parsed : [parsed];
				} catch {
					// JSON parse failed — might be an array with some bad elements.
					// Strip outer array brackets and re-extract individual objects.
					let innerStr = jsonStr.trim();
					if (innerStr.startsWith('[') && innerStr.endsWith(']')) {
						innerStr = innerStr.slice(1, -1);
					}
					const inner = extractCompleteJsonObjects(innerStr);
					if (inner.objects.length > 0) {
						const parsed: unknown[] = [];
						for (const s of inner.objects) {
							try { parsed.push(JSON.parse(s)); } catch {
								errorCount++;
								yield { type: 'error', stage: 'parsing' as const, message: `JSON parse error: malformed object` };
							}
						}
						candidates = parsed;
						if (candidates.length === 0) continue;
					} else {
						// Truly unparseable
						errorCount++;
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `JSON parse error: unparseable content`
						};
						yield event;
						console.info('[decompose-service] JSON parse error: unparseable content');
						continue;
					}
				}

				for (const candidate of candidates) {
					const result = decomposeModuleSchema.safeParse(candidate);

					if (result.success) {
						const event: DecomposeModuleEvent = {
							type: 'module',
							index: moduleIndex++,
							module: result.data
						};
						yield event;
					} else {
						errorCount++;
						const detail = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `Zod validation failed: ${detail}`
						};
						yield event;
						console.info('[decompose-service] Zod validation failed for module:', detail);
					}
				}
			}
		}

		// Phase 2: Handle any remaining buffer (partial object at end of stream)
		if (jsonBuffer.trim()) {
			// Try wrapping in array brackets if it looks like the LLM forgot them
			let finalBuffer = jsonBuffer.trim();
			if (!finalBuffer.startsWith('[') && !finalBuffer.startsWith('{')) {
				finalBuffer = `[${finalBuffer}]`;
			}

			const { objects } = extractCompleteJsonObjects(finalBuffer);
			for (const jsonStr of objects) {
				let candidates: unknown[];
				try {
					const parsed = JSON.parse(jsonStr);
					candidates = Array.isArray(parsed) ? parsed : [parsed];
				} catch (parseErr: any) {
					errorCount++;
					const event: DecomposeErrorEvent = {
						type: 'error',
						stage: 'parsing',
						message: `JSON parse error on remaining buffer: ${parseErr.message}`
					};
					yield event;
					continue;
				}

				for (const candidate of candidates) {
					const result = decomposeModuleSchema.safeParse(candidate);
					if (result.success) {
						const event: DecomposeModuleEvent = {
							type: 'module',
							index: moduleIndex++,
							module: result.data
						};
						yield event;
					} else {
						errorCount++;
						const detail = result.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join('; ');
						const event: DecomposeErrorEvent = {
							type: 'error',
							stage: 'parsing',
							message: `Zod validation failed: ${detail}`
						};
						yield event;
					}
				}
			}
		}
	} catch (err: any) {
		errorCount++;
		// Classify the error stage
		let stage: 'connecting' | 'streaming' | 'parsing' = 'connecting';
		if (moduleIndex > 0) {
			stage = 'streaming';
		}
		const event: DecomposeErrorEvent = {
			type: 'error',
			stage,
			message: err.message
		};
		yield event;
		console.info('[decompose-service] Stream error:', err.message);
	} finally {
		const doneEvent: DecomposeDoneEvent = {
			type: 'done',
			total: moduleIndex,
			errors: errorCount
		};
		yield doneEvent;
		console.info('[decompose-service] Stream complete:', { total: moduleIndex, errors: errorCount });
	}
}

